// Beacon — ambient type shims.
// The @fontsource side-effect packages ship CSS only — no .d.ts. Declaring
// the module here silences TS without pulling in a separate `@types/*`.
declare module "@fontsource-variable/inter";
declare module "@fontsource-variable/fraunces";
declare module "@fontsource/jetbrains-mono/400.css";
declare module "@fontsource/jetbrains-mono/500.css";
